// ============================================
// CLIENT CONFIGURATION - EDIT THIS SECTION
// ============================================
const CLIENT_NAME = 'Codesec Technologies';
const CLIENT_ADDRESS = 'Chennai, Tamil Nadu, India';
const REPORT_EMAIL = 'naveen@codesecure.in';
const MANAGER_NAME = 'ip-192-168-133-24';
const OPENSEARCH_URL = 'https://172.17.0.1:9200';
const OPENSEARCH_AUTH = 'Basic YWRtaW46bXBwN05ITk9tU3k4Y0FjMmlBcCpBaGdVYUU3aytsVEI=';
// ============================================

return [{
  json: {
    client_name: CLIENT_NAME,
    client_address: CLIENT_ADDRESS,
    report_email: REPORT_EMAIL,
    manager_name: MANAGER_NAME,
    opensearch_url: OPENSEARCH_URL,
    opensearch_auth: OPENSEARCH_AUTH
  }
}];

const config = $('Client Config').first().json;
const data = $input.first().json;
const aggs = data.aggregations;
const totalHits = data.hits.total.value;

// IST dates
const now = new Date();
const istOptions = { timeZone: 'Asia/Kolkata' };
const istDate = now.toLocaleDateString('en-IN', { ...istOptions, day: '2-digit', month: '2-digit', year: 'numeric' });
const istTime = now.toLocaleTimeString('en-IN', { ...istOptions, hour12: true, hour: '2-digit', minute: '2-digit' });
const yesterday = new Date(now - 86400000);
const fromDate = yesterday.toISOString().split('.')[0];
const toDate = now.toISOString().split('.')[0];

// Severity mapping
const severityMap = {
  0: { label: 'Info', color: '#6c757d' },
  1: { label: 'Info', color: '#6c757d' },
  2: { label: 'Info', color: '#6c757d' },
  3: { label: 'Low', color: '#17a2b8' },
  4: { label: 'Low', color: '#17a2b8' },
  5: { label: 'Medium', color: '#ffc107' },
  6: { label: 'Medium', color: '#ffc107' },
  7: { label: 'High', color: '#fd7e14' },
  8: { label: 'High', color: '#fd7e14' },
  9: { label: 'High', color: '#fd7e14' },
  10: { label: 'Critical', color: '#dc3545' },
  11: { label: 'Critical', color: '#dc3545' },
  12: { label: 'Critical', color: '#dc3545' },
  13: { label: 'Critical', color: '#dc3545' },
  14: { label: 'Critical', color: '#dc3545' },
  15: { label: 'Critical', color: '#dc3545' }
};

// Process severity levels
const levelBuckets = aggs.alerts_by_level.buckets;
const severityCounts = { Critical: 0, High: 0, Medium: 0, Low: 0, Info: 0 };
levelBuckets.forEach(b => {
  const sev = severityMap[b.key] || { label: 'Info' };
  severityCounts[sev.label] += b.doc_count;
});

// Top rules
const topRules = aggs.top_rules.buckets.map(b => ({
  rule_id: b.key,
  description: b.rule_desc.buckets[0]?.key || 'N/A',
  level: b.rule_level.buckets[0]?.key || 0,
  count: b.doc_count
})).sort((a, b) => b.level - a.level || b.count - a.count);

// Top agents
const topAgents = aggs.top_agents.buckets.map(b => ({
  name: b.key,
  count: b.doc_count
}));

// MITRE
const mitreTechniques = aggs.mitre_techniques.buckets.map(b => ({
  technique: b.key,
  count: b.doc_count
}));
const mitreTactics = aggs.mitre_tactics.buckets.map(b => ({
  tactic: b.key,
  count: b.doc_count
}));

// Hourly timeline
const timeline = aggs.alerts_over_time.buckets.map(b => ({
  hour: new Date(b.key_as_string).toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit', hour12: false }),
  count: b.doc_count
}));

// Level evolution (for chart)
const levelEvolution = aggs.top_rule_level_evolution.buckets.map(b => {
  const levels = {};
  b.levels.buckets.forEach(lb => { levels[lb.key] = lb.doc_count; });
  return {
    time: new Date(b.key_as_string).toLocaleTimeString('en-IN', { timeZone: 'Asia/Kolkata', hour: '2-digit', minute: '2-digit', hour12: false }),
    ...levels
  };
});

return [{
  json: {
    client_name: config.client_name,
    client_address: config.client_address,
    report_email: config.report_email,
    manager_name: config.manager_name,
    total_alerts: totalHits,
    severity_counts: severityCounts,
    top_rules: topRules,
    top_agents: topAgents,
    mitre_techniques: mitreTechniques,
    mitre_tactics: mitreTactics,
    timeline: timeline,
    level_evolution: levelEvolution,
    level_buckets: levelBuckets,
    from_date: fromDate,
    to_date: toDate,
    ist_date: istDate,
    ist_time: istTime
  }
}];

const d = $input.first().json;
const sc = d.severity_counts;
const sevDef = [
  { key:'Critical', color:'#e74c3c', icon:'!!' },
  { key:'High', color:'#e67e22', icon:'!' },
  { key:'Medium', color:'#f1c40f', icon:'~' },
  { key:'Low', color:'#3498db', icon:'-' },
  { key:'Info', color:'#95a5a6', icon:'i' }
];

// SVG Donut chart
function svgDonut(data, w, h) {
  const cx=w/2, cy=h/2, r=60, r2=40;
  const total = data.reduce((s,d)=>s+d.value,0) || 1;
  let cumAngle = -90;
  const paths = data.filter(d=>d.value>0).map(d => {
    const pct = d.value/total;
    const angle = pct*360;
    const startAngle = cumAngle * Math.PI/180;
    const endAngle = (cumAngle+angle) * Math.PI/180;
    cumAngle += angle;
    const largeArc = angle > 180 ? 1 : 0;
    const x1=cx+r*Math.cos(startAngle), y1=cy+r*Math.sin(startAngle);
    const x2=cx+r*Math.cos(endAngle), y2=cy+r*Math.sin(endAngle);
    const x3=cx+r2*Math.cos(endAngle), y3=cy+r2*Math.sin(endAngle);
    const x4=cx+r2*Math.cos(startAngle), y4=cy+r2*Math.sin(startAngle);
    return `<path d="M${x1},${y1} A${r},${r} 0 ${largeArc},1 ${x2},${y2} L${x3},${y3} A${r2},${r2} 0 ${largeArc},0 ${x4},${y4}Z" fill="${d.color}"/>`;
  }).join('');
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${paths}<text x="${cx}" y="${cy-5}" text-anchor="middle" font-size="16" font-weight="bold" fill="#2c3e50">${total.toLocaleString()}</text><text x="${cx}" y="${cy+10}" text-anchor="middle" font-size="8" fill="#7f8c8d">Total</text></svg>`;
}

// SVG Vertical bar chart
function svgVertBars(items, w, h, showLabels) {
  const pad={t:10,b:showLabels?45:20,l:5,r:5};
  const chartW=w-pad.l-pad.r, chartH=h-pad.t-pad.b;
  const max=Math.max(...items.map(i=>i.value),1);
  const barW=Math.min(Math.floor(chartW/items.length)-2, 30);
  const gap=(chartW-barW*items.length)/(items.length+1);
  let bars='';
  items.forEach((item,i) => {
    const barH=Math.max((item.value/max)*chartH, 2);
    const x=pad.l+gap+(barW+gap)*i;
    const y=pad.t+chartH-barH;
    bars+=`<rect x="${x}" y="${y}" width="${barW}" height="${barH}" fill="${item.color||'#3498db'}" rx="2"/>`;
    if(showLabels) {
      bars+=`<text x="${x+barW/2}" y="${pad.t+chartH+10}" text-anchor="middle" font-size="6" fill="#7f8c8d" transform="rotate(45,${x+barW/2},${pad.t+chartH+10})">${item.label}</text>`;
    }
    bars+=`<text x="${x+barW/2}" y="${y-3}" text-anchor="middle" font-size="6" fill="#555">${item.value>=1000?(item.value/1000).toFixed(0)+'k':item.value}</text>`;
  });
  // baseline
  bars+=`<line x1="${pad.l}" y1="${pad.t+chartH}" x2="${w-pad.r}" y2="${pad.t+chartH}" stroke="#ddd" stroke-width="1"/>`;
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${bars}</svg>`;
}

// SVG Horizontal bar chart
function svgHorizBars(items, w, h) {
  const pad={t:5,b:5,l:120,r:60};
  const chartW=w-pad.l-pad.r;
  const barH=Math.min(Math.floor((h-pad.t-pad.b)/items.length)-4, 18);
  const max=Math.max(...items.map(i=>i.value),1);
  let bars='';
  items.forEach((item,i) => {
    const bw=Math.max((item.value/max)*chartW, 3);
    const y=pad.t+(barH+4)*i;
    bars+=`<text x="${pad.l-6}" y="${y+barH/2+3}" text-anchor="end" font-size="7" fill="#2c3e50">${item.label.length>18?item.label.substring(0,18)+'...':item.label}</text>`;
    bars+=`<rect x="${pad.l}" y="${y}" width="${bw}" height="${barH}" fill="${item.color||'#3498db'}" rx="3"/>`;
    bars+=`<text x="${pad.l+bw+4}" y="${y+barH/2+3}" font-size="7" font-weight="bold" fill="#2c3e50">${item.value.toLocaleString()}</text>`;
  });
  return `<svg width="${w}" height="${h}" viewBox="0 0 ${w} ${h}">${bars}</svg>`;
}

// Donut data
const donutData = sevDef.map(s=>({value:sc[s.key],color:s.color,label:s.key}));
const donutSvg = svgDonut(donutData, 160, 160);
const donutLegend = sevDef.map(s=>`<div style="display:flex;align-items:center;margin:3px 0"><div style="width:12px;height:12px;border-radius:2px;background:${s.color};margin-right:6px"></div><span style="font-size:9px;width:55px">${s.key}</span><span style="font-size:9px;font-weight:bold">${sc[s.key].toLocaleString()}</span></div>`).join('');

// Timeline vertical bars
const tlColors = d.timeline.map(t=>'#3498db');
const timelineItems = d.timeline.map((t,i)=>({value:t.count,label:t.hour,color:'#3498db'}));
const timelineSvg = svgVertBars(timelineItems, 750, 140, true);

// Agents horizontal bars
const agentPalette = ['#2ecc71','#3498db','#9b59b6','#e67e22','#1abc9c','#e74c3c','#f39c12','#2980b9','#8e44ad','#16a085'];
const agentItems = d.top_agents.map((a,i)=>({value:a.count,label:a.name,color:agentPalette[i%10]}));
const agentSvg = svgHorizBars(agentItems, 380, Math.max(agentItems.length*22+10, 80));

// MITRE techniques
const mitrePalette = ['#e74c3c','#e67e22','#f1c40f','#2ecc71','#1abc9c','#3498db','#9b59b6','#34495e','#e91e63','#00bcd4','#8bc34a','#ff5722','#607d8b','#795548','#cddc39'];
const techItems = d.mitre_techniques.map((m,i)=>({value:m.count,label:m.technique,color:mitrePalette[i%15]}));
const techSvg = svgHorizBars(techItems, 380, Math.max(techItems.length*22+10, 80));

// MITRE tactics
const tacticItems = d.mitre_tactics.map((m,i)=>({value:m.count,label:m.tactic,color:mitrePalette[i%15]}));
const tacticSvg = svgHorizBars(tacticItems, 380, Math.max(tacticItems.length*22+10, 80));

// Alerts table - SORTED BY LEVEL DESC then count desc
const sortedRules = [...d.top_rules].sort((a,b) => b.level - a.level || b.count - a.count);
const ruleRows = sortedRules.map((r, i) => {
  const lc = r.level>=10?'#e74c3c':r.level>=7?'#e67e22':r.level>=5?'#f1c40f':r.level>=3?'#3498db':'#95a5a6';
  const tc = r.level>=5?'#fff':'#fff';
  const bg = i%2===0?'#fff':'#f7f9fc';
  return `<tr style="background:${bg}"><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;text-align:center;font-weight:700;color:#2c3e50">${r.rule_id}</td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;font-size:7.5px;color:#34495e">${r.description.length>120?r.description.substring(0,120)+'...':r.description}</td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;text-align:center"><span style="background:${lc};color:${tc};padding:2px 8px;border-radius:10px;font-size:7px;font-weight:700">${r.level}</span></td><td style="padding:5px 8px;border-bottom:1px solid #ecf0f1;text-align:right;font-weight:700;color:#2c3e50">${r.count.toLocaleString()}</td></tr>`;
}).join('');

// Severity stat cards
const statCards = sevDef.map(s => `<div style="flex:1;text-align:center;padding:12px 8px;background:linear-gradient(135deg,${s.color}15,${s.color}08);border-radius:8px;border:1px solid ${s.color}30;position:relative;overflow:hidden"><div style="position:absolute;top:-10px;right:-5px;font-size:40px;opacity:0.08;font-weight:900">${s.icon}</div><div style="font-size:22px;font-weight:800;color:${s.color};letter-spacing:-0.5px">${sc[s.key].toLocaleString()}</div><div style="font-size:8px;color:#7f8c8d;margin-top:3px;text-transform:uppercase;letter-spacing:1px">${s.key}</div></div>`).join('');

const htmlReport = `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<title>Threat Hunting Report</title>
<style>
@page{size:A4 landscape;margin:0.3in}
*{margin:0;padding:0;box-sizing:border-box}
body{font-family:'Segoe UI',Arial,sans-serif;font-size:9px;color:#2c3e50;background:#fff}
.page{page-break-after:always;padding:12px 20px;position:relative}
.page:last-child{page-break-after:auto}
.card{background:#fff;border-radius:10px;box-shadow:0 2px 8px rgba(0,0,0,0.06);padding:14px;margin-bottom:12px;border:1px solid #ecf0f1}
.section-title{font-size:13px;font-weight:700;color:#2c3e50;margin:0 0 10px;padding:6px 0;border-bottom:2px solid #3498db;display:flex;align-items:center}
.section-title .dot{width:8px;height:8px;border-radius:50%;background:#3498db;margin-right:8px}
.header-bar{background:linear-gradient(135deg,#2c3e50,#3498db);color:#fff;padding:16px 24px;border-radius:10px;margin-bottom:14px}
.header-bar h1{font-size:22px;font-weight:800;margin-bottom:4px;letter-spacing:-0.5px}
.header-bar p{font-size:9px;opacity:0.85}
.two-col{display:flex;gap:14px}
.two-col>div{flex:1}
.footer{position:fixed;bottom:8px;left:20px;right:20px;text-align:center;font-size:7px;color:#bdc3c7;border-top:1px solid #ecf0f1;padding-top:4px}
table{width:100%;border-collapse:collapse;font-size:8px}
thead th{background:linear-gradient(135deg,#2c3e50,#34495e);color:#fff;padding:6px 8px;text-align:left;font-size:7.5px;text-transform:uppercase;letter-spacing:0.5px}
</style>
</head>
<body>

<!-- PAGE 1: Executive Summary -->
<div class="page">
  <div class="header-bar">
    <h1>Threat Hunting Report</h1>
    <p>Security alerts analysis for <strong>${d.client_name}</strong> &bull; ${d.client_address}</p>
    <p style="margin-top:4px">${d.from_date} &rarr; ${d.to_date} &bull; Manager: ${d.manager_name}</p>
  </div>

  <div style="display:flex;gap:10px;margin-bottom:14px">${statCards}</div>

  <div class="two-col">
    <div class="card">
      <div class="section-title"><span class="dot"></span>Severity Distribution</div>
      <div style="display:flex;align-items:center;justify-content:center;gap:20px">
        ${donutSvg}
        <div>${donutLegend}</div>
      </div>
    </div>
    <div class="card">
      <div class="section-title"><span class="dot"></span>Top ${d.top_agents.length} Agents</div>
      ${agentSvg}
    </div>
  </div>

  <div class="card">
    <div class="section-title"><span class="dot"></span>Alerts Timeline (24h)</div>
    ${timelineSvg}
  </div>
</div>

<!-- PAGE 2: MITRE ATT&CK -->
<div class="page">
  <div class="header-bar" style="padding:10px 24px">
    <h1 style="font-size:16px">MITRE ATT&CK Analysis</h1>
    <p>Techniques and tactics detected in the last 24 hours</p>
  </div>

  <div class="two-col">
    <div class="card">
      <div class="section-title"><span class="dot" style="background:#e74c3c"></span>Top Techniques</div>
      ${techSvg}
    </div>
    <div class="card">
      <div class="section-title"><span class="dot" style="background:#e67e22"></span>Top Tactics</div>
      ${tacticSvg}
    </div>
  </div>
</div>

<!-- PAGE 3+: Alerts Summary -->
<div class="page">
  <div class="header-bar" style="padding:10px 24px">
    <h1 style="font-size:16px">Alerts Summary</h1>
    <p>All rules sorted by severity level (Critical &rarr; Low) &bull; ${sortedRules.length} unique rules</p>
  </div>

  <div class="card" style="padding:0;overflow:hidden">
    <table>
      <thead>
        <tr>
          <th style="width:55px;text-align:center">Rule ID</th>
          <th>Description</th>
          <th style="width:45px;text-align:center">Level</th>
          <th style="width:70px;text-align:right;padding-right:12px">Count</th>
        </tr>
      </thead>
      <tbody>${ruleRows}</tbody>
    </table>
  </div>
</div>

<div class="footer">
  <strong>${d.client_name}</strong> &bull; ${d.client_address} &bull; Report generated: ${d.ist_date} ${d.ist_time} &bull; Wazuh SIEM Automated Report
</div>

</body>
</html>`;

return [{
  json: {
    html_report: htmlReport,
    total_records: d.total_alerts,
    report_date: d.ist_date,
    report_email: d.report_email,
    file_name: 'security_report_' + new Date().toISOString().split('T')[0].replace(/-/g,'') + '.html'
  }
}];

const input = $input.all()[0].json;

return [{
  json: input,
  binary: {
    data: {
      data: Buffer.from(input.html_report, 'utf8'),
      mimeType: 'text/html',
      fileName: 'index.html'
    }
  }
}];
